/**
 * Webhook notification handler — fires HTTP callbacks when order events occur.
 *
 * Provides a webhook registry where external URLs can be registered for
 * specific event types. When events occur, registered webhooks are called
 * with a JSON payload containing the event data.
 *
 * Integrates with the existing notification architecture using BOTH patterns:
 * - EventBus subscription for order:created events
 * - CallbackRegistry for order:status-changed events
 *
 * This mirrors the approach used in NotificationService and EmailNotificationHandler.
 *
 * Depends on:
 * - EventBus (event system) for order:created events
 * - CallbackRegistry (direct callbacks) for order:status-changed events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  registeredAt: Date;
}

export interface WebhookDelivery {
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  deliveredAt: Date;
  success: boolean;
  error?: string;
}

export type WebhookSender = (url: string, payload: Record<string, unknown>) => Promise<void>;

let nextWebhookId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextWebhookId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(private eventBus: EventBus, sender?: WebhookSender) {
    this.sender = sender ?? WebhookHandler.defaultSender;
    this.registerHandlers();
  }

  /**
   * Default sender that performs an HTTP POST (in-memory no-op for demo).
   */
  private static async defaultSender(_url: string, _payload: Record<string, unknown>): Promise<void> {
    // In production this would be fetch(url, { method: 'POST', body: JSON.stringify(payload), ... })
  }

  /**
   * Register event handlers for webhook dispatch.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern),
   * matching the existing NotificationService approach.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      registeredAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} -> ${url} for ${eventType}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registered webhooks for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook by ID.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  /**
   * Handle order created — dispatch to registered webhooks.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const payload: Record<string, unknown> = {
      eventType: event.type,
      orderId: event.order.id,
      userId: event.order.userId,
      items: event.order.items,
      total: event.order.total,
      status: event.order.status,
      timestamp: event.timestamp.toISOString(),
    };

    await this.dispatchWebhooks('order:created', payload);
  }

  /**
   * Handle order status change — dispatch to registered webhooks.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const payload: Record<string, unknown> = {
      eventType: event.type,
      orderId: event.order.id,
      userId: event.order.userId,
      previousStatus: event.previousStatus,
      newStatus: event.newStatus,
      timestamp: event.timestamp.toISOString(),
    };

    // CallbackRegistry is synchronous, so we fire-and-forget
    void this.dispatchWebhooks('order:status-changed', payload);
  }

  /**
   * Dispatch payloads to all webhooks registered for a given event type.
   */
  private async dispatchWebhooks(eventType: EventType, payload: Record<string, unknown>): Promise<void> {
    const hooks = this.getRegistrationsForEvent(eventType);
    if (hooks.length === 0) {
      return;
    }

    this.logger.info(`Dispatching ${eventType} to ${hooks.length} webhook(s)`);

    for (const hook of hooks) {
      let success = true;
      let error: string | undefined;

      try {
        await this.sender(hook.url, payload);
      } catch (err) {
        success = false;
        error = err instanceof Error ? err.message : String(err);
        this.logger.error(`Webhook delivery failed for ${hook.id}: ${error}`);
      }

      this.deliveries.push({
        webhookId: hook.id,
        url: hook.url,
        eventType,
        payload,
        deliveredAt: new Date(),
        success,
        error,
      });
    }
  }
}

